// AppIcon.swift
// The OpenAudio glyph, embedded so it renders in the UI (routing bus nodes)
// regardless of build path — `swift run`, build-app.sh bundle, or Xcode — where
// NSApplication.applicationIconImage is unreliable. Source: Tools/App/icon.icon
// (Icon Composer) → actool → icns → 64px PNG. Regenerate if the icon changes.

import AppKit

enum AppIcon {
    /// The app's icon as an NSImage, decoded once from the embedded PNG.
    static let image: NSImage = {
        if let data = Data(base64Encoded: pngBase64), let img = NSImage(data: data) {
            return img
        }
        return NSApplication.shared.applicationIconImage
    }()

    private static let pngBase64 = """

"""
}
